    chryses_figures = [
        {
            "name": "Chryses (Danaide)",
            "parentage": "Son of Zeus and Isonoe",
            "role": "One of the Danaides"
        },
        {
            "name": "Chryses (King of Orchomenus)",
            "parentage": "Son of Poseidon and Chrysogeneia",
            "role": "King of Orchomenus, possible father of Minyas"
        },
        {
            "name": "Chryses (Son of Minos)",
            "parentage": "Son of Minos and Pareia",
            "role": "Lived in Paros, killed by Heracles"
        },
        {
            "name": "Chryses (Trojan Priest)",
            "parentage": "Not specified in the text",
            "role": "Father of Chryseis"
        },
        {
            "name": "Chryses (Grandson of Agamemnon)",
